// Lifecycle statuses for content processing.
// Ref: #/components/schemas/ContentStatus
type ContentStatus string

const (
	ContentStatusNew        ContentStatus = "new"
	ContentStatusPending    ContentStatus = "pending"
	ContentStatusProcessing ContentStatus = "processing"
	ContentStatusCompleted  ContentStatus = "completed"
	ContentStatusFailed     ContentStatus = "failed"
	ContentStatusSkipped    ContentStatus = "skipped"
)

// AllValues returns all ContentStatus values.
func (ContentStatus) AllValues() []ContentStatus {
	return []ContentStatus{
		ContentStatusNew,
		ContentStatusPending,
		ContentStatusProcessing,
		ContentStatusCompleted,
		ContentStatusFailed,
		ContentStatusSkipped,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s ContentStatus) MarshalText() ([]byte, error) {
	switch s {
	case ContentStatusNew:
		return []byte(s), nil
	case ContentStatusPending:
		return []byte(s), nil
	case ContentStatusProcessing:
		return []byte(s), nil
	case ContentStatusCompleted:
		return []byte(s), nil
	case ContentStatusFailed:
		return []byte(s), nil
	case ContentStatusSkipped:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *ContentStatus) UnmarshalText(data []byte) error {
	switch ContentStatus(data) {
	case ContentStatusNew:
		*s = ContentStatusNew
		return nil
	case ContentStatusPending:
		*s = ContentStatusPending
		return nil
	case ContentStatusProcessing:
		*s = ContentStatusProcessing
		return nil
	case ContentStatusCompleted:
		*s = ContentStatusCompleted
		return nil
	case ContentStatusFailed:
		*s = ContentStatusFailed
		return nil
	case ContentStatusSkipped:
		*s = ContentStatusSkipped
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

