// Supported content types in storage and API contracts.
// Ref: #/components/schemas/ContentType
type ContentType string

const (
	ContentTypeArticle ContentType = "article"
	ContentTypePodcast ContentType = "podcast"
	ContentTypeNews    ContentType = "news"
	ContentTypeUnknown ContentType = "unknown"
)

// AllValues returns all ContentType values.
func (ContentType) AllValues() []ContentType {
	return []ContentType{
		ContentTypeArticle,
		ContentTypePodcast,
		ContentTypeNews,
		ContentTypeUnknown,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s ContentType) MarshalText() ([]byte, error) {
	switch s {
	case ContentTypeArticle:
		return []byte(s), nil
	case ContentTypePodcast:
		return []byte(s), nil
	case ContentTypeNews:
		return []byte(s), nil
	case ContentTypeUnknown:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *ContentType) UnmarshalText(data []byte) error {
	switch ContentType(data) {
	case ContentTypeArticle:
		*s = ContentTypeArticle
		return nil
	case ContentTypePodcast:
		*s = ContentTypePodcast
		return nil
	case ContentTypeNews:
		*s = ContentTypeNews
		return nil
	case ContentTypeUnknown:
		*s = ContentTypeUnknown
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

